// Parse and validate input
const body = $input.first().json.body;

// Support both patientName and title for blocking
const eventTitle = body.title || body.patientName;

// Required fields
if (!eventTitle) {
  throw new Error('Име на пациент или заглавие е задължително');
}
if (!body.date) {
  throw new Error('Дата е задължителна');
}
if (!body.startTime) {
  throw new Error('Начален час е задължителен');
}

// Calculate end time based on duration or endTime
let endTime;
if (body.endTime) {
  endTime = body.endTime;
} else {
  const duration = body.duration || 30;
  const startDate = new Date(`${body.date}T${body.startTime}:00`);
  const endDate = new Date(startDate.getTime() + duration * 60 * 1000);
  endTime = `${String(endDate.getHours()).padStart(2, '0')}:${String(endDate.getMinutes()).padStart(2, '0')}`;
}

// Appointment status handling
const statusVal = body.status || 'confirmed';
const statusLabels = { 'pending': 'Чакащ', 'confirmed': 'Потвърден', 'completed': 'Завършен' };
const statusLabel = statusLabels[statusVal] || 'Потвърден';

// Reminder flag (admin-controlled). Default: off.
const sendReminder = body.sendReminder === true || body.sendReminder === 'true';

// Build summary - add ⏳ prefix for pending
let summary = eventTitle;
if (statusVal === 'pending') {
  summary = '⏳ ' + eventTitle;
}

// Build description with structured data
let description = '';
if (body.patientPhone) {
  description += `📞 Тел: ${body.patientPhone}\n`;
}
if (body.patientEmail) {
  description += `✉️ Имейл: ${body.patientEmail}\n`;
}
if (body.procedure) {
  description += `🦷 Процедура: ${body.procedure}\n`;
}
description += `📋 Статус: ${statusLabel}\n`;
description += `🔔 Напомняне: ${sendReminder ? 'ДА' : 'НЕ'}\n`;
if (body.notes) {
  description += `📝 Бележки: ${body.notes}\n`;
}

// Map color names to Google Calendar colorId (1-11)
const colorMap = {
  'green': '10', 'blue': '9', 'red': '11', 'yellow': '5',
  'purple': '3', 'orange': '6', 'pink': '4', 'gray': '8'
};
const statusColorDefaults = { 'pending': 'yellow', 'completed': 'gray', 'confirmed': 'green' };
const effectiveColor = body.colorId || statusColorDefaults[statusVal] || 'green';
const googleColorId = colorMap[effectiveColor] || colorMap['green'];

return [{
  json: {
    summary: summary,
    description: description.trim(),
    startDateTime: `${body.date}T${body.startTime}:00`,
    endDateTime: `${body.date}T${endTime}:00`,
    date: body.date,
    duration: body.duration || 30,
    patientName: body.patientName || eventTitle,
    patientPhone: body.patientPhone || '',
    procedure: body.procedure || '',
    status: statusVal,
    sendReminder: sendReminder,
    colorId: googleColorId
  }
}];

// Get created event details
const event = $input.first().json;
const prevData = $('Prepare Event Data').first().json;

return [{
  json: {
    id: event.id,
    googleEventId: event.id,
    title: event.summary,
    patientName: prevData.patientName,
    patientPhone: prevData.patientPhone,
    procedure: prevData.procedure,
    date: prevData.date,
    duration: prevData.duration,
    status: prevData.status || 'confirmed',
    htmlLink: event.htmlLink,
    created: event.created,
    updated: event.updated
  }
}];
